# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import pymysql
import json

def lambda_handler(event, context):
    # Database connection parameters
    db_host = 'your-rds-endpoint'
    db_user = 'your-username'
    db_password = 'your-password'
    db_name = 'your-database-name'

    # Connect to the RDS MySQL database
    connection = pymysql.connect(
        host=db_host,
        user=db_user,
        password=db_password,
        database=db_name,
        cursorclass=pymysql.cursors.DictCursor
    )

    try:
        with connection.cursor() as cursor:
            # Extract search parameters from API Gateway event
            search_params = event.get('queryStringParameters', {})
            product_name = search_params.get('name')
            min_price = search_params.get('minPrice')
            max_price = search_params.get('maxPrice')

            # Build SQL query dynamically based on the provided parameters
            sql = "SELECT * FROM products WHERE 1=1"
            params = []

            if product_name:
                sql += " AND name LIKE %s"
                params.append(f'%{product_name}%')
            
            if min_price:
                sql += " AND price >= %s"
                params.append(float(min_price))
            
            if max_price:
                sql += " AND price <= %s"
                params.append(float(max_price))

            # Execute the query
            cursor.execute(sql, params)
            results = cursor.fetchall()

        # Return the results as a JSON response
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
            },
            'body': json.dumps(results),
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)}),
        }
    finally:
        connection.close()